import React, { useEffect, useState } from "react";
import "./App.css";
import AddAssignment from "./components/AddAssignment";
import AssignmentList from "./components/AssignmentList";
import Stats from "./components/Stats";
import Login from "./components/Login";

function App() {
  const [userId, setUserId] = useState(localStorage.getItem("userId"));
  const [assignments, setAssignments] = useState([]);
  const [stats, setStats] = useState({});

  // Fetch assignments and stats
  const fetchData = async () => {
    if (!userId) return;

    try {
      const a = await fetch(`http://localhost:8080/assignments/user/${userId}`);
      const s = await fetch(`http://localhost:8080/assignments/stats/${userId}`);

      const assignmentsData = await a.json();
      const statsData = await s.json();

      setAssignments(assignmentsData);
      setStats(statsData);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    fetchData();
  }, [userId]);

  // ✅ Submit assignment
  const submitAssignment = async (id) => {
    try {
      const response = await fetch(`http://localhost:8080/assignments/submit/${id}`, {
        method: "PUT",
      });
      if (response.ok) {
        fetchData(); // auto-refresh after submit
      } else {
        alert("Failed to submit assignment");
      }
    } catch (error) {
      console.error(error);
    }
  };

  // ✅ Delete assignment
  const deleteAssignment = async (id) => {
    const confirmDelete = window.confirm("⚠️ Are you sure you want to delete this assignment?");
    if (!confirmDelete) return;

    try {
      const response = await fetch(`http://localhost:8080/assignments/delete/${id}`, {
        method: "DELETE",
      });
      if (response.ok) {
        fetchData(); // auto-refresh after delete
      } else {
        alert("Failed to delete assignment");
      }
    } catch (error) {
      console.error(error);
    }
  };

  // Logout
  const logout = () => {
    localStorage.removeItem("userId");
    setUserId(null); // important
  };

  // 🔹 If NOT logged in → show Login page
  if (!userId) {
    return <Login setUserId={setUserId} />;
  }

  // 🔹 If logged in → show Dashboard
  return (
    <div className="app-container">
      <h1>AssignTrack - Assignment Submission Tracker</h1>

      <button onClick={logout}>Logout</button>

      <AddAssignment refresh={fetchData} userId={userId} />

      <AssignmentList
        assignments={assignments}
        submit={submitAssignment}      // submit handler
        deleteAssignment={deleteAssignment} // delete handler
      />

      <Stats stats={stats} />
    </div>
  );
}

export default App;
